#[test]
fn test_result_tables_empty_when_no_tables() {
    // Result tables array is empty when input has no tables
    let html = r#"<p>No tables here</p>"#;
    let options_json: serde_json::Value = serde_json::from_str(r#"{"include_document_structure":true}"#).unwrap();
    let options: ConversionOptions = serde_json::from_value(options_json).unwrap();
    let result = convert(html, Some(options.clone())).expect("should succeed");
    assert!(result.content.is_some(), "expected content to be present");
    assert_eq!(
        result.tables.len(),
        0,
        "expected exactly 0 elements, got {}",
        result.tables.len()
    );
}

#[test]
fn test_result_tables_multiple() {
    // Multiple tables each appear in the tables array
    let html = r#"<table><tr><th>A</th></tr><tr><td>1</td></tr></table><p>Between</p><table><tr><th>B</th></tr><tr><td>2</td></tr></table>"#;
    let options_json: serde_json::Value = serde_json::from_str(r#"{"include_document_structure":true}"#).unwrap();
    let options: ConversionOptions = serde_json::from_value(options_json).unwrap();
    let result = convert(html, Some(options.clone())).expect("should succeed");
    assert!(
        result.tables.len() >= 2,
        "expected at least 2 elements, got {}",
        result.tables.len()
    );
}

#[test]
fn test_result_tables_simple() {
    // Simple table populates the tables array in result
    let html = r#"<table><thead><tr><th>Name</th><th>Age</th></tr></thead><tbody><tr><td>Alice</td><td>30</td></tr></tbody></table>"#;
    let options_json: serde_json::Value = serde_json::from_str(r#"{"include_document_structure":true}"#).unwrap();
    let options: ConversionOptions = serde_json::from_value(options_json).unwrap();
    let result = convert(html, Some(options.clone())).expect("should succeed");
    assert!(result.content.is_some(), "expected content to be present");
    assert!(!result.tables.is_empty(), "expected >= 1");
}

