#[test]
fn test_result_warning_kind_image_extraction_failed() {
    // A malformed data URI with extract_images enabled produces an ImageExtractionFailed warning
    let html = r#"<p>Text<img src="data:BADMIME" alt="broken">end</p>"#;
    let options_json: serde_json::Value = serde_json::from_str(r#"{"extract_images":true}"#).unwrap();
    let options: ConversionOptions = serde_json::from_value(options_json).unwrap();
    let result = convert(html, Some(options.clone())).expect("should succeed");
    assert!(result.content.is_some(), "expected content to be present");
    assert!(!result.warnings.is_empty(), "expected >= 1");
}

